import React, { useState } from 'react';
import { jsPDF } from 'jspdf';
import axios from 'axios';
import AlertMessage from './shared/AlertMessage';
import LoadingSpinner from './shared/LoadingSpinner';

const CertificateGenerator = () => {
  const [formData, setFormData] = useState({
    recipientName: '',
    program: '',
    issueDate: new Date().toISOString().split('T')[0]
  });
  
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(null);
  const [error, setError] = useState(null);
  const [certificate, setCertificate] = useState(null);
  
  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.recipientName || formData.recipientName.trim().length < 3) {
      newErrors.recipientName = 'Name must be at least 3 characters';
    }
    
    if (!formData.program) {
      newErrors.program = 'Program is required';
    }
    
    if (!formData.issueDate) {
      newErrors.issueDate = 'Issue date is required';
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };
  
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };
  
  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) {
      return;
    }
    
    setLoading(true);
    setError(null);
    setSuccess(null);
    
    try {
      const token = localStorage.getItem('token');
      
      if (!token) {
        throw new Error('Authentication required');
      }
      
      const response = await axios.post(
        'http://localhost:5001/api/certificates/siu/generate',
        formData,
        {
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          }
        }
      );
      
      setSuccess('Certificate generated successfully!');
      setCertificate(response.data.data.certificate);
      
    } catch (err) {
      console.error('Error generating certificate:', err);
      setError(err.response?.data?.message || err.message || 'Failed to generate certificate');
    } finally {
      setLoading(false);
    }
  };
  
  const handleDownload = async () => {
    if (!certificate) return;
    
    try {
      setLoading(true);
      
      // Create a new PDF document
      const doc = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4'
      });
      
      // Set background (simulating the template)
      doc.setFillColor(255, 255, 255);
      doc.rect(0, 0, 297, 210, 'F');
      
      // Add gold border
      doc.setDrawColor(212, 160, 23); // #D4A017
      doc.setLineWidth(1);
      doc.rect(10, 10, 277, 190);
      
      // Set text colors
      doc.setTextColor(0, 48, 135); // #003087 deep blue
      
      // Add SIU header
      doc.setFontSize(24);
      doc.setFont('helvetica', 'bold');
      doc.text('STRATFORD INTERNATIONAL UNIVERSITY', 148.5, 30, { align: 'center' });
      
      // Certificate title
      doc.setFontSize(36);
      doc.text('Certificate of Completion', 148.5, 50, { align: 'center' });
      
      doc.setFontSize(20);
      doc.text('毕业证书', 148.5, 60, { align: 'center' });
      
      // Recipient details
      doc.setTextColor(0, 0, 0); // Black
      doc.setFontSize(18);
      doc.setFont('helvetica', 'normal');
      doc.text('This is to certify that', 148.5, 80, { align: 'center' });
      
      doc.setFontSize(30);
      doc.setFont('helvetica', 'bolditalic');
      doc.text(certificate.recipientName, 148.5, 100, { align: 'center' });
      
      doc.setFontSize(18);
      doc.setFont('helvetica', 'normal');
      doc.text('has successfully completed the requirements for', 148.5, 120, { align: 'center' });
      
      doc.setFontSize(24);
      doc.setFont('helvetica', 'bold');
      doc.text(certificate.program, 148.5, 140, { align: 'center' });
      
      // Certificate details
      doc.setFontSize(10);
      doc.setFont('helvetica', 'normal');
      doc.text(`Certificate Number: ${certificate.certificateNumber}`, 148.5, 160, { align: 'center' });
      doc.text(`Issue Date: ${new Date(certificate.issueDate).toLocaleDateString()}`, 148.5, 166, { align: 'center' });
      doc.text(`Blockchain Hash: ${certificate.blockchainHash}`, 148.5, 172, { align: 'center' });
      
      // Signatures
      doc.setFontSize(10);
      doc.line(80, 180, 120, 180);
      doc.text('Dr. Elizabeth Stratford', 100, 186, { align: 'center' });
      doc.text('University President', 100, 192, { align: 'center' });
      
      doc.line(180, 180, 220, 180);
      doc.text('Prof. Michael Abide', 200, 186, { align: 'center' });
      doc.text('Program Director', 200, 192, { align: 'center' });
      
      // Download the PDF
      doc.save(`SIU-Certificate-${certificate.certificateNumber}.pdf`);
      
    } catch (err) {
      console.error('Error downloading certificate:', err);
      setError('Failed to download certificate: ' + err.message);
    } finally {
      setLoading(false);
    }
  };
  
  return (
    <div className="max-w-2xl mx-auto my-8 p-6 bg-white rounded-lg shadow-lg">
      <h2 className="text-2xl font-bold text-blue-900 mb-6 text-center">Stratford International University Certificate Generator</h2>
      
      {error && (
        <AlertMessage
          type="error"
          message={{ title: "Error", details: error }}
          className="mb-4"
        />
      )}
      
      {success && (
        <AlertMessage
          type="success"
          message={{ title: "Success", details: success }}
          className="mb-4"
        />
      )}
      
      {loading ? (
        <LoadingSpinner message="Processing certificate..." />
      ) : (
        <>
          {certificate ? (
            <div className="mb-6 p-4 bg-gray-50 rounded-lg">
              <h3 className="text-lg font-semibold mb-3">Certificate Generated!</h3>
              <p className="mb-1"><span className="font-semibold">Name:</span> {certificate.recipientName}</p>
              <p className="mb-1"><span className="font-semibold">Program:</span> {certificate.program}</p>
              <p className="mb-1"><span className="font-semibold">Certificate Number:</span> {certificate.certificateNumber}</p>
              <p className="mb-3"><span className="font-semibold">Issue Date:</span> {new Date(certificate.issueDate).toLocaleDateString()}</p>
              
              <button
                onClick={handleDownload}
                className="w-full py-2 px-4 bg-blue-900 hover:bg-blue-800 text-white font-medium rounded-md focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
              >
                Download Certificate (PDF)
              </button>
            </div>
          ) : (
            <form onSubmit={handleSubmit}>
              <div className="mb-4">
                <label htmlFor="recipientName" className="block text-gray-700 font-medium mb-2">
                  Full Name
                </label>
                <input
                  type="text"
                  id="recipientName"
                  name="recipientName"
                  value={formData.recipientName}
                  onChange={handleChange}
                  className={`w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                    errors.recipientName ? 'border-red-500' : 'border-gray-300'
                  }`}
                  placeholder="Enter recipient's full name"
                />
                {errors.recipientName && (
                  <p className="text-red-500 text-sm mt-1">{errors.recipientName}</p>
                )}
              </div>
              
              <div className="mb-4">
                <label htmlFor="program" className="block text-gray-700 font-medium mb-2">
                  Program/Degree
                </label>
                <select
                  id="program"
                  name="program"
                  value={formData.program}
                  onChange={handleChange}
                  className={`w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                    errors.program ? 'border-red-500' : 'border-gray-300'
                  }`}
                >
                  <option value="">Select a program</option>
                  <option value="BSc in Business Administration">BSc in Business Administration</option>
                  <option value="MSc in International Business">MSc in International Business</option>
                  <option value="MBA in Global Management">MBA in Global Management</option>
                  <option value="PhD in Business Economics">PhD in Business Economics</option>
                  <option value="Certificate in Digital Marketing">Certificate in Digital Marketing</option>
                  <option value="Diploma in Project Management">Diploma in Project Management</option>
                </select>
                {errors.program && (
                  <p className="text-red-500 text-sm mt-1">{errors.program}</p>
                )}
              </div>
              
              <div className="mb-6">
                <label htmlFor="issueDate" className="block text-gray-700 font-medium mb-2">
                  Issue Date
                </label>
                <input
                  type="date"
                  id="issueDate"
                  name="issueDate"
                  value={formData.issueDate}
                  onChange={handleChange}
                  className={`w-full px-3 py-2 border rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 ${
                    errors.issueDate ? 'border-red-500' : 'border-gray-300'
                  }`}
                />
                {errors.issueDate && (
                  <p className="text-red-500 text-sm mt-1">{errors.issueDate}</p>
                )}
              </div>
              
              <button
                type="submit"
                disabled={loading}
                className="w-full py-2 px-4 bg-blue-900 hover:bg-blue-800 text-white font-medium rounded-md shadow-sm focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
              >
                Generate Certificate
              </button>
            </form>
          )}
          
          {certificate && (
            <button
              onClick={() => setCertificate(null)}
              className="w-full mt-4 py-2 px-4 bg-gray-100 hover:bg-gray-200 text-gray-800 font-medium rounded-md focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-gray-500"
            >
              Generate Another Certificate
            </button>
          )}
        </>
      )}
    </div>
  );
};

export default CertificateGenerator;
